import React from "react";
import CommonTable from "../../../components/CommonTable";

function SchemeMastersTable({ module }) {
   return (
      <div className="card border-0 shadow-sm">
         <div className="card-header border-0" style={{ background: module.bg, borderLeft: `5px solid ${module.color}` }} >
            <div className="d-flex align-items-center">
                <div><h5 className="card-title mb-0 fw-bold">
                  {module.listTitle}
               </h5>
               <small> All {module.listSubTitle} added to the system. </small></div>
            </div>
         </div>
         <div className="card-body text-center py-5" style={{ minHeight: "600px" }} >
            <div class="text-center text-secondary px-3">
               <div class="rounded-circle d-inline-flex align-items-center justify-content-center mb-3"
                  style={{width:"64px",height:"64px",background:module.bg}}>
                  <i class="fa fa-file-text-o fa-2x" style={{color:module.color}}></i>
                  </div>
                  <div class="fw-semibold text-dark mb-1">No {module.listSubTitle} yet</div>
                  <div className="small" style={{maxWidth:"240px"}}>Use the form on the right to add your first {module.listSubTitle}.</div>
               </div>
            </div>
         </div>
   );
}

export default SchemeMastersTable;
